import * as fs from 'fs';
import * as path from 'path';
import * as os from 'os';
// @ts-ignore
import Dirty from '../../../../../../../../../../../subject_repositories/node-dirty/lib/dirty/dirty.js';

describe('Dirty close() with autoClose disabled', () => {
  it('should emit write_close even when autoClose would not trigger it', (done) => {
    const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), 'dirty-test-'));
    const dbPath = path.join(tmpDir, 'test.db');

    // Patch createWriteStream to use autoClose: false
    const originalCreate = fs.createWriteStream;
    (fs as any).createWriteStream = (path: any, opts: any) => {
      return originalCreate(path, { ...opts, autoClose: false });
    };

    const db = new Dirty(dbPath);

    // Restore immediately after construction
    (fs as any).createWriteStream = originalCreate;

    db.once('load', () => {
      let writeCloseFired = false;
      db.once('write_close', () => { writeCloseFired = true; });

      db.close();

      const failTimeout = setTimeout(() => {
        try { fs.rmSync(tmpDir, { recursive: true }); } catch (e) {}
        done(new Error('write_close was not emitted - destroy() was not called to close the stream'));
      }, 300);

      db.once('write_close', () => {
        clearTimeout(failTimeout);
        try { fs.rmSync(tmpDir, { recursive: true }); } catch (e) {}
        done();
      });
    });
  });
});
```

With `autoClose: false`, the stream won't auto-close after `end()`. The only way `'close'` fires (and thus `write_close`) is if `destroy()` is explicitly called. This should be the definitive test!

